import React, { useState, useRef, useEffect, useCallback } from 'react';
import axios from 'axios';
import {
  LineChart, Line, AreaChart, Area,
  XAxis, YAxis, CartesianGrid, Tooltip,
  ResponsiveContainer, PieChart, Pie, Cell, Legend
} from 'recharts';
import SlidingLogin from './components/SlidingLogin';
import OnboardingForm from './components/OnboardingForm';
import '@fortawesome/fontawesome-free/css/all.min.css';

const API = 'http://localhost:5000';

/* ──────────────────────────────────────────────────
   HELPERS DE ESTILO
────────────────────────────────────────────────── */
const DARK = {
  bg:         'linear-gradient(135deg,#05091a 0%,#0d1530 60%,#05091a 100%)',
  navBg:      'rgba(5,9,26,0.92)',
  card:       'rgba(13,21,48,0.75)',
  border:     'rgba(39,139,245,0.18)',
  text:       '#e8eef8',
  textMuted:  '#8899bb',
  primary:    '#278BF5',
  accent:     '#00e5c8',
};
const LIGHT = {
  bg:         'linear-gradient(135deg,#e8f4fd 0%,#dbeafe 60%,#e8f4fd 100%)',
  navBg:      'rgba(255,255,255,0.92)',
  card:       'rgba(255,255,255,0.75)',
  border:     'rgba(39,139,245,0.22)',
  text:       '#0f1e3c',
  textMuted:  '#4a6080',
  primary:    '#1a6fd8',
  accent:     '#00a896',
};

function card(t) {
  return {
    background:    t.card,
    backdropFilter:'blur(14px)',
    border:        `1px solid ${t.border}`,
    borderRadius:  18,
    padding:       '20px 22px',
    marginBottom:  18,
  };
}

/* ──────────────────────────────────────────────────
   COMPONENTES UI REUTILIZABLES
────────────────────────────────────────────────── */
function SectionTitle({ icon, label, color = '#278BF5', t }) {
  return (
    <div style={{ display:'flex', alignItems:'center', gap:10, marginBottom:16 }}>
      <div style={{
        background:`linear-gradient(135deg,${color}33,${color}11)`,
        border:`1px solid ${color}44`,
        borderRadius:10, width:34, height:34,
        display:'flex', alignItems:'center', justifyContent:'center',
        fontSize:15,
      }}>{icon}</div>
      <span style={{ color:t.text, fontWeight:700, fontSize:16 }}>{label}</span>
    </div>
  );
}

function StatBox({ label, value, sub, color='#278BF5', t }) {
  return (
    <div style={{
      background:`${color}11`, border:`1px solid ${color}28`,
      borderRadius:14, padding:'16px 14px', textAlign:'center', flex:1,
    }}>
      <div style={{ fontSize:28, fontWeight:800, color, letterSpacing:'-1px' }}>{value}</div>
      <div style={{ fontSize:12, fontWeight:600, color:t.text, marginTop:3 }}>{label}</div>
      {sub && <div style={{ fontSize:11, color:t.textMuted, marginTop:2 }}>{sub}</div>}
    </div>
  );
}

function Badge({ nivel }) {
  const cfg = {
    1:{ bg:'rgba(16,185,129,.15)', color:'#10b981', border:'rgba(16,185,129,.3)', label:'Normal' },
    2:{ bg:'rgba(245,158,11,.15)', color:'#f59e0b', border:'rgba(245,158,11,.3)', label:'Moderada' },
    3:{ bg:'rgba(239,68,68,.15)',  color:'#ef4444', border:'rgba(239,68,68,.3)',  label:'Alta' },
  };
  const c = cfg[nivel] || cfg[1];
  return (
    <span style={{
      background:c.bg, color:c.color,
      border:`1px solid ${c.border}`,
      borderRadius:30, padding:'4px 14px',
      fontSize:12, fontWeight:700,
    }}>{c.label}</span>
  );
}

/* ──────────────────────────────────────────────────
   SECCIÓN: PERFIL EDITABLE
────────────────────────────────────────────────── */
function SeccionPerfil({ user, perfil, onSave, t }) {
  const [edit, setEdit]   = useState(false);
  const [saving, setSaving] = useState(false);
  const [form, setForm]   = useState({
    puesto:            perfil?.trabajo?.puesto || '',
    empresa:           perfil?.trabajo?.empresa || '',
    tipo_trabajo:      perfil?.trabajo?.tipo_trabajo || '',
    turno:             perfil?.trabajo?.turno || '',
    horas_jornada:     perfil?.trabajo?.horas_jornada || 8,
    deportes:          perfil?.actividad_fisica?.deportes?.join(', ') || '',
    horas_sueno:       perfil?.actividad_fisica?.horas_sueno || 7,
    notas_salud:       perfil?.salud_facial?.notas || '',
  });

  const field = (key, label, type='text', min, max) => (
    <div style={{ marginBottom:14 }}>
      <label style={{ display:'block', fontSize:11, fontWeight:600, color:t.textMuted,
        textTransform:'uppercase', letterSpacing:'0.7px', marginBottom:6 }}>{label}</label>
      <input
        type={type} disabled={!edit}
        value={form[key]} min={min} max={max}
        onChange={e => setForm(f => ({ ...f, [key]: e.target.value }))}
        style={{
          width:'100%', boxSizing:'border-box',
          background: edit ? `${t.primary}09` : 'transparent',
          border: `1px solid ${edit ? t.primary+'55' : t.border}`,
          borderRadius:10, padding:'10px 12px',
          color:t.text, fontSize:13,
          outline:'none', transition:'all .2s',
          cursor: edit ? 'text' : 'default',
        }}
      />
    </div>
  );

  const handleSave = async () => {
    setSaving(true);
    try {
      await axios.put(`${API}/perfil_salud/${user.id_usuario}`, {
        trabajo: {
          puesto:        form.puesto,
          empresa:       form.empresa,
          tipo_trabajo:  form.tipo_trabajo,
          turno:         form.turno,
          horas_jornada: parseInt(form.horas_jornada),
        },
        actividad_fisica: {
          deportes:           form.deportes.split(',').map(s=>s.trim()).filter(Boolean),
          horas_sueno:        parseFloat(form.horas_sueno),
        },
        salud_facial: {
          ...perfil?.salud_facial,
          notas: form.notas_salud,
        },
      });
      onSave();
      setEdit(false);
    } catch { alert('Error al guardar cambios'); }
    finally { setSaving(false); }
  };

  return (
    <div>
      {/* Info no editable */}
      <div style={{ ...card(t), background:`${t.primary}09`, marginBottom:14 }}>
        <div style={{ display:'flex', alignItems:'center', gap:10, marginBottom:4 }}>
          <span style={{ fontSize:22 }}>🔒</span>
          <span style={{ color:t.textMuted, fontSize:12 }}>
            Datos de cuenta — no editables por seguridad
          </span>
        </div>
        <div style={{ display:'flex', gap:32, flexWrap:'wrap' }}>
          {[['Nombre', user.nombre],['Correo', user.email],['ID de usuario', `#${user.id_usuario}`]].map(([k,v]) => (
            <div key={k}>
              <div style={{ fontSize:11, color:t.textMuted }}>{k}</div>
              <div style={{ fontWeight:700, color:t.text, fontSize:14 }}>{v}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Condiciones faciales (solo lectura) */}
      <div style={card(t)}>
        <SectionTitle icon="🧬" label="Condiciones faciales" color="#7c3aed" t={t} />
        <div style={{ display:'flex', flexWrap:'wrap', gap:8 }}>
          {(perfil?.salud_facial?.condiciones || ['ninguna']).map(c => (
            <span key={c} style={{
              background:`rgba(124,58,237,.12)`, border:`1px solid rgba(124,58,237,.25)`,
              color:'#a78bfa', borderRadius:20, padding:'4px 12px', fontSize:12,
            }}>{c}</span>
          ))}
        </div>
        {perfil?.salud_facial?.notas && (
          <div style={{ marginTop:10, fontSize:12, color:t.textMuted }}>
            📝 {perfil.salud_facial.notas}
          </div>
        )}
      </div>

      {/* Trabajo + Actividad */}
      <div style={card(t)}>
        <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:18 }}>
          <SectionTitle icon="💼" label="Trabajo & Actividad" color={t.primary} t={t} />
          {!edit
            ? <button onClick={() => setEdit(true)} style={{
                background:`${t.primary}22`, border:`1px solid ${t.primary}44`,
                color:t.primary, borderRadius:20, padding:'7px 18px',
                fontSize:12, fontWeight:600, cursor:'pointer',
              }}>✏️ Editar</button>
            : <div style={{ display:'flex', gap:8 }}>
                <button onClick={() => setEdit(false)} style={{
                  background:'transparent', border:`1px solid ${t.border}`,
                  color:t.textMuted, borderRadius:20, padding:'7px 14px',
                  fontSize:12, cursor:'pointer',
                }}>Cancelar</button>
                <button onClick={handleSave} disabled={saving} style={{
                  background:`linear-gradient(135deg,${t.primary},#0a5fd8)`,
                  border:'none', color:'white', borderRadius:20,
                  padding:'7px 18px', fontSize:12, fontWeight:700, cursor:'pointer',
                  opacity: saving ? 0.7 : 1,
                }}>{ saving ? '...' : '✅ Guardar'}</button>
              </div>
          }
        </div>
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'0 24px' }}>
          {field('puesto', 'Puesto / Cargo')}
          {field('empresa', 'Empresa')}
          {field('tipo_trabajo', 'Tipo de trabajo')}
          {field('turno', 'Turno')}
          {field('horas_jornada', 'Horas de jornada', 'number', 4, 16)}
          {field('horas_sueno', 'Horas de sueño promedio', 'number', 3, 12)}
        </div>
        {field('deportes', 'Actividades / Deportes (separados por coma)')}
        {field('notas_salud', 'Notas de salud adicionales')}
      </div>
    </div>
  );
}

/* ──────────────────────────────────────────────────
   SECCIÓN: HISTORIAL & GRÁFICAS
────────────────────────────────────────────────── */
const PIE_COLORS = ['#10b981','#f59e0b','#ef4444'];
const NIVEL_LABEL = { 1:'Normal', 2:'Moderada', 3:'Alta' };

function CustomTooltipFatiga({ active, payload, label }) {
  if (!active || !payload?.length) return null;
  const c = { 1:'#10b981', 2:'#f59e0b', 3:'#ef4444' };
  return (
    <div style={{
      background:'rgba(13,21,48,.95)', border:'1px solid rgba(39,139,245,.2)',
      borderRadius:10, padding:'10px 14px', fontSize:12,
    }}>
      <p style={{ color:'#8899bb', margin:'0 0 4px 0' }}>{label}</p>
      {payload.map((p,i) => (
        <p key={i} style={{ color:c[p.value] || p.color, margin:0, fontWeight:700 }}>
          {p.name}: {NIVEL_LABEL[p.value] || p.value}
        </p>
      ))}
    </div>
  );
}

function SeccionHistorial({ userId, t }) {
  const [logs, setLogs]     = useState([]);
  const [resumen, setRes]   = useState(null);
  const [loading, setLoad]  = useState(true);
  const [rango, setRango]   = useState(50);

  const cargar = useCallback(async () => {
    setLoad(true);
    try {
      const [rL, rR] = await Promise.all([
        axios.get(`${API}/historial_fatiga/${userId}?limit=${rango}`),
        axios.get(`${API}/resumen_fatiga/${userId}`),
      ]);
      // Invertir para mostrar cronológico (más viejo → más nuevo)
      const data = [...(rL.data || [])].reverse().map((d, i) => ({
        ...d,
        idx:   i + 1,
        hora:  d.fecha_hora ? new Date(d.fecha_hora).toLocaleTimeString('es-MX',{hour:'2-digit',minute:'2-digit'}) : `#${i+1}`,
        label: NIVEL_LABEL[d.nivel_fatiga] || 'Normal',
      }));
      setLogs(data);
      setRes(rR.data);
    } catch { /* silencioso */ }
    finally { setLoad(false); }
  }, [userId, rango]);

  useEffect(() => { cargar(); }, [cargar]);

  // Datos para pie
  const pieData = resumen ? [
    { name:'Normal',   value: resumen.nivel_1 || 0 },
    { name:'Moderada', value: resumen.nivel_2 || 0 },
    { name:'Alta',     value: resumen.nivel_3 || 0 },
  ] : [];

  // EAR promedio por hora para area chart
  const earData = logs.slice(-30).map(d => ({
    hora:  d.hora,
    ear:   d.ear_value,
    nivel: d.nivel_fatiga,
  }));

  if (loading) return (
    <div style={{ textAlign:'center', padding:40, color:t.textMuted }}>
      <div style={{ fontSize:28, marginBottom:8 }}>⏳</div>Cargando historial...
    </div>
  );

  return (
    <div>
      {/* Resumen numérico */}
      {resumen && (
        <div style={card(t)}>
          <SectionTitle icon="📊" label="Resumen de sesiones" color={t.primary} t={t} />
          <div style={{ display:'flex', gap:12, flexWrap:'wrap' }}>
            <StatBox label="Total registros"  value={resumen.total || 0}          color={t.primary} t={t} />
            <StatBox label="EAR promedio"     value={(resumen.ear_promedio||0).toFixed(2)} color="#7c3aed" t={t} sub="Apertura ocular" />
            <StatBox label="% Tiempo normal"  value={`${resumen.pct_normal||0}%`} color="#10b981" t={t} />
            <StatBox label="Nivel promedio"   value={(resumen.nivel_promedio||1).toFixed(1)} color="#f59e0b" t={t} sub="sobre 3" />
          </div>
        </div>
      )}

      {/* Gráficas */}
      <div style={{ display:'grid', gridTemplateColumns:'2fr 1fr', gap:18, marginBottom:18 }}>

        {/* Área de niveles en el tiempo */}
        <div style={card(t)}>
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:14 }}>
            <SectionTitle icon="📈" label="Nivel de fatiga en el tiempo" color="#f59e0b" t={t} />
            <div style={{ display:'flex', gap:6 }}>
              {[20,50,100].map(n => (
                <button key={n} onClick={() => setRango(n)} style={{
                  background: rango===n ? `${t.primary}22` : 'transparent',
                  border:`1px solid ${rango===n ? t.primary : t.border}`,
                  color: rango===n ? t.primary : t.textMuted,
                  borderRadius:20, padding:'4px 12px', fontSize:11,
                  cursor:'pointer', fontWeight: rango===n ? 700 : 400,
                }}>Últimos {n}</button>
              ))}
            </div>
          </div>
          <ResponsiveContainer width="100%" height={200}>
            <AreaChart data={logs} margin={{ top:5, right:10, left:-20, bottom:0 }}>
              <defs>
                <linearGradient id="nivelGrad" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%"  stopColor="#f59e0b" stopOpacity={0.3}/>
                  <stop offset="95%" stopColor="#f59e0b" stopOpacity={0}/>
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" stroke={`${t.border}`} />
              <XAxis dataKey="hora" tick={{ fill:t.textMuted, fontSize:10 }} interval="preserveStartEnd" />
              <YAxis domain={[1,3]} ticks={[1,2,3]}
                tickFormatter={v => ['','Normal','Mod.','Alta'][v] || v}
                tick={{ fill:t.textMuted, fontSize:10 }} />
              <Tooltip content={<CustomTooltipFatiga />} />
              <Area type="monotone" dataKey="nivel_fatiga" name="Fatiga"
                stroke="#f59e0b" fill="url(#nivelGrad)" strokeWidth={2} dot={false} />
            </AreaChart>
          </ResponsiveContainer>
        </div>

        {/* Pie distribución */}
        <div style={card(t)}>
          <SectionTitle icon="🥧" label="Distribución" color="#00e5c8" t={t} />
          {pieData.some(d => d.value > 0) ? (
            <ResponsiveContainer width="100%" height={200}>
              <PieChart>
                <Pie data={pieData} cx="50%" cy="45%" outerRadius={70}
                  dataKey="value" nameKey="name"
                  label={({ name, percent }) => `${(percent*100).toFixed(0)}%`}
                  labelLine={false}>
                  {pieData.map((_, i) => (
                    <Cell key={i} fill={PIE_COLORS[i]} />
                  ))}
                </Pie>
                <Legend formatter={(v) => <span style={{ color:t.textMuted, fontSize:11 }}>{v}</span>} />
                <Tooltip formatter={(v) => [`${v} registros`]} />
              </PieChart>
            </ResponsiveContainer>
          ) : (
            <div style={{ textAlign:'center', color:t.textMuted, padding:40, fontSize:12 }}>
              Sin datos suficientes
            </div>
          )}
        </div>
      </div>

      {/* EAR en el tiempo */}
      <div style={card(t)}>
        <SectionTitle icon="👁️" label="Apertura ocular (EAR) — últimas 30 lecturas" color="#7c3aed" t={t} />
        <ResponsiveContainer width="100%" height={160}>
          <LineChart data={earData} margin={{ top:5, right:10, left:-20, bottom:0 }}>
            <CartesianGrid strokeDasharray="3 3" stroke={t.border} />
            <XAxis dataKey="hora" tick={{ fill:t.textMuted, fontSize:10 }} interval="preserveStartEnd" />
            <YAxis domain={[0.1, 0.4]} tick={{ fill:t.textMuted, fontSize:10 }} />
            <Tooltip
              contentStyle={{ background:'rgba(13,21,48,.95)', border:`1px solid ${t.border}`, borderRadius:10 }}
              labelStyle={{ color:t.textMuted }} itemStyle={{ color:'#7c3aed' }}
            />
            {/* Líneas de umbrales */}
            <Line type="monotone" dataKey="ear" name="EAR" stroke="#7c3aed"
              strokeWidth={2} dot={false} />
          </LineChart>
        </ResponsiveContainer>
        <div style={{ display:'flex', gap:16, marginTop:8 }}>
          <span style={{ fontSize:11, color:'#ef4444' }}>— Fatiga alta (&lt;0.21)</span>
          <span style={{ fontSize:11, color:'#f59e0b' }}>— Fatiga mod. (&lt;0.26)</span>
          <span style={{ fontSize:11, color:'#10b981' }}>— Normal (≥0.26)</span>
        </div>
      </div>

      {/* Tabla de logs */}
      <div style={card(t)}>
        <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:14 }}>
          <SectionTitle icon="📋" label="Registros recientes" color={t.primary} t={t} />
          <button onClick={cargar} style={{
            background:`${t.primary}15`, border:`1px solid ${t.border}`,
            color:t.primary, borderRadius:20, padding:'6px 14px',
            fontSize:11, cursor:'pointer', fontWeight:600,
          }}>🔄 Actualizar</button>
        </div>
        <div style={{ overflowX:'auto' }}>
          <table style={{ width:'100%', borderCollapse:'collapse', fontSize:12 }}>
            <thead>
              <tr>
                {['#','Hora','Nivel','EAR','Estado'].map(h => (
                  <th key={h} style={{
                    textAlign:'left', padding:'8px 12px',
                    color:t.textMuted, fontWeight:600, fontSize:11,
                    borderBottom:`1px solid ${t.border}`,
                    textTransform:'uppercase', letterSpacing:'0.6px',
                  }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {logs.slice().reverse().slice(0,15).map((d, i) => (
                <tr key={i} style={{ borderBottom:`1px solid ${t.border}33` }}>
                  <td style={{ padding:'8px 12px', color:t.textMuted }}>{d.idx}</td>
                  <td style={{ padding:'8px 12px', color:t.text }}>{d.hora}</td>
                  <td style={{ padding:'8px 12px' }}><Badge nivel={d.nivel_fatiga} /></td>
                  <td style={{ padding:'8px 12px', color:
                    d.ear_value < 0.21 ? '#ef4444' : d.ear_value < 0.26 ? '#f59e0b' : '#10b981',
                    fontWeight:700, fontFamily:'monospace',
                  }}>{(d.ear_value||0).toFixed(3)}</td>
                  <td style={{ padding:'8px 12px', color:t.textMuted }}>
                    {d.nivel_fatiga === 3 ? '🔴 Alta' : d.nivel_fatiga === 2 ? '🟡 Moderada' : '🟢 Normal'}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {logs.length === 0 && (
            <div style={{ textAlign:'center', padding:'28px 0', color:t.textMuted, fontSize:13 }}>
              Aún no hay registros de fatiga. Inicia una sesión de monitoreo.
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

/* ──────────────────────────────────────────────────
   APP PRINCIPAL
────────────────────────────────────────────────── */
export default function App() {
  const [user, setUser]       = useState(null);
  const [appState, setAppState] = useState('loading');
  const [perfil, setPerfil]   = useState(null);
  const [isDark, setIsDark]   = useState(true);
  const [tab, setTab]         = useState('inicio'); // inicio | historial | perfil
  const [nivelFatiga, setNivel] = useState(1);
  const [estadoFatiga, setEstado] = useState('Iniciando...');
  const videoRef = useRef(null);
  const t = isDark ? DARK : LIGHT;

  // ── Sesión guardada ──────────────────────────────
  useEffect(() => {
    const saved = localStorage.getItem('prolife_user');
    if (saved) {
      const u = JSON.parse(saved);
      setUser(u);
      checkOnboarding(u);
    } else {
      setAppState('login');
    }
  }, []);

  const checkOnboarding = async (u) => {
    try {
      const r = await axios.get(`${API}/perfil_salud/${u.id_usuario}`);
      if (r.data?.trabajo) { setPerfil(r.data); setAppState('dashboard'); startCamera(); }
      else setAppState('onboarding');
    } catch { setAppState('onboarding'); }
  };

  const recargarPerfil = async () => {
    if (!user) return;
    try {
      const r = await axios.get(`${API}/perfil_salud/${user.id_usuario}`);
      setPerfil(r.data);
    } catch {}
  };

  // ── Cámara ───────────────────────────────────────
  const startCamera = async () => {
    try {
      const s = await navigator.mediaDevices.getUserMedia({ video:{ facingMode:'user' } });
      if (videoRef.current) videoRef.current.srcObject = s;
    } catch (e) { console.error('Cámara:', e); }
  };

  useEffect(() => {
    let iv;
    if (appState === 'dashboard') {
      iv = setInterval(async () => {
        if (!videoRef.current || videoRef.current.readyState < 2) return;
        const c = document.createElement('canvas');
        c.width  = videoRef.current.videoWidth;
        c.height = videoRef.current.videoHeight;
        c.getContext('2d').drawImage(videoRef.current, 0, 0);
        try {
          const r = await axios.post(`${API}/analizar_fatiga`, {
            image: c.toDataURL('image/jpeg'),
            id_usuario: user.id_usuario,
          });
          setNivel(r.data.nivel || 1);
          setEstado(r.data.estado || 'Normal');
        } catch {}
      }, 2000);
    }
    return () => clearInterval(iv);
  }, [appState, user]);

  // ── Abrir Streamlit con token ────────────────────
  const abrirDeteccion = async () => {
    try {
      const r = await axios.post(`${API}/session_token`, { id_usuario: user.id_usuario });
      window.open(`http://localhost:8501?token=${r.data.token}`, '_blank');
    } catch { alert('No se pudo iniciar la sesión de detección. Verifica que el servidor esté activo.'); }
  };

  const handleLogin = (u) => {
    console.log('Usuario al login:', u);
    setUser(u); localStorage.setItem('prolife_user', JSON.stringify(u));
    checkOnboarding(u);
  };
  const handleLogout = () => {
    videoRef.current?.srcObject?.getTracks().forEach(t => t.stop());
    setUser(null); setAppState('login');
    localStorage.removeItem('prolife_user');
  };

  // ── Pantallas simples ────────────────────────────
  if (appState === 'loading') return (
    <div style={{ minHeight:'100vh', display:'flex', alignItems:'center', justifyContent:'center',
      background:'#05091a', flexDirection:'column', gap:12 }}>
      <div style={{ fontSize:36 }}>⚡</div>
      <p style={{ color:'#8899bb', fontFamily:'Sora,sans-serif', margin:0 }}>Cargando ProLife...</p>
    </div>
  );
  if (appState === 'login')     return <SlidingLogin onLogin={handleLogin} />;
  if (appState === 'onboarding') return <OnboardingForm user={user} onComplete={() => checkOnboarding(user)} />;

  // ── DASHBOARD ────────────────────────────────────
  const hora   = new Date().getHours();
  const saludo = hora < 12 ? 'Buenos días' : hora < 18 ? 'Buenas tardes' : 'Buenas noches';
  const nivelCfg = {
    1:{ color:'#10b981', texto:'Normal',          icono:'😊', desc:'Tu nivel de energía es óptimo.' },
    2:{ color:'#f59e0b', texto:'Fatiga moderada', icono:'😐', desc:'Signos de cansancio. Toma un descanso breve.' },
    3:{ color:'#ef4444', texto:'Fatiga alta',     icono:'😴', desc:'Descansa ahora. Es importante.' },
  };
  const nc = nivelCfg[nivelFatiga] || nivelCfg[1];

  const TABS = [
    { id:'inicio',   label:'Inicio',   icon:'🏠' },
    { id:'historial',label:'Historial',icon:'📊' },
    { id:'perfil',   label:'Mi Perfil',icon:'👤' },
  ];

  return (
    <div style={{ minHeight:'100vh', background:t.bg, fontFamily:"'Sora','Inter',sans-serif",
      color:t.text, transition:'all .3s' }}>

      {/* ── NAV ── */}
      <nav style={{
        background:t.navBg, backdropFilter:'blur(16px)',
        borderBottom:`1px solid ${t.border}`,
        padding:'12px 28px', display:'flex', justifyContent:'space-between',
        alignItems:'center', position:'sticky', top:0, zIndex:100,
        flexWrap:'wrap', gap:10,
      }}>
        <div style={{ display:'flex', alignItems:'center', gap:10 }}>
          <div style={{ background:'linear-gradient(135deg,#278BF5,#00e5c8)',
            width:36, height:36, borderRadius:10, display:'flex',
            alignItems:'center', justifyContent:'center', fontSize:18, flexShrink:0 }}>⚡</div>
          <div>
            <div style={{ fontWeight:800, fontSize:16, letterSpacing:'-0.3px' }}>ProLife</div>
            <div style={{ fontSize:10, color:t.textMuted }}>Energy Co-pilot</div>
          </div>
        </div>

        {/* Tabs */}
        <div style={{ display:'flex', gap:4, background:`${t.border}`, borderRadius:30, padding:4 }}>
          {TABS.map(tab_ => (
            <button key={tab_.id} onClick={() => setTab(tab_.id)} style={{
              background: tab === tab_.id
                ? `linear-gradient(135deg,${t.primary},#0a5fd8)`
                : 'transparent',
              border:'none', borderRadius:24, padding:'7px 18px',
              color: tab === tab_.id ? 'white' : t.textMuted,
              fontSize:12, fontWeight: tab===tab_.id ? 700 : 500,
              cursor:'pointer', transition:'all .2s', display:'flex', alignItems:'center', gap:6,
            }}>
              <span>{tab_.icon}</span><span>{tab_.label}</span>
            </button>
          ))}
        </div>

        <div style={{ display:'flex', alignItems:'center', gap:12, flexWrap:'wrap' }}>
          <div style={{ fontSize:12, textAlign:'right' }}>
            <div style={{ color:t.textMuted, fontSize:10 }}>{saludo}</div>
            <div style={{ fontWeight:700 }}>{user.nombre.split(' ')[0]}</div>
          </div>
          <button onClick={() => setIsDark(!isDark)} style={{
            background:`${t.border}`, border:`1px solid ${t.border}`,
            borderRadius:20, padding:'6px 12px', cursor:'pointer',
            color:t.textMuted, fontSize:11,
          }}>{ isDark ? '☀️ Claro' : '🌙 Oscuro'}</button>
          <button onClick={handleLogout} style={{
            background:'rgba(239,68,68,.12)', border:'1px solid rgba(239,68,68,.25)',
            color:'#ef4444', borderRadius:20, padding:'6px 14px',
            fontSize:12, fontWeight:600, cursor:'pointer',
          }}>Salir</button>
        </div>
      </nav>

      {/* ── CONTENIDO ── */}
      <div style={{ maxWidth:1100, margin:'0 auto', padding:'24px 20px' }}>

        {/* ═══ TAB: INICIO ═══ */}
        {tab === 'inicio' && (
          <div>
            {/* Fila superior: video + estado actual */}
            <div style={{ display:'grid', gridTemplateColumns:'3fr 2fr', gap:18, marginBottom:18 }}>

              {/* Video */}
              <div style={card(t)}>
                <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:14 }}>
                  <SectionTitle icon="📹" label="Cámara en vivo" color="#10b981" t={t} />
                  <div style={{ display:'flex', alignItems:'center', gap:6, fontSize:11, color:'#10b981' }}>
                    <div style={{ width:7, height:7, borderRadius:'50%', background:'#10b981',
                      boxShadow:'0 0 8px #10b981', animation:'pulse 2s infinite' }} />
                    Activo
                  </div>
                </div>
                <video ref={videoRef} autoPlay playsInline muted style={{
                  width:'100%', borderRadius:12, background:'#000',
                  boxShadow:'0 4px 20px rgba(0,0,0,.3)', display:'block',
                }} />
              </div>

              {/* Estado + botón */}
              <div style={{ display:'flex', flexDirection:'column', gap:14 }}>

                {/* Estado actual */}
                <div style={{ ...card(t), flex:1, display:'flex', flexDirection:'column',
                  alignItems:'center', justifyContent:'center', textAlign:'center', gap:8 }}>
                  <div style={{ fontSize:44 }}>{nc.icono}</div>
                  <div style={{ fontWeight:800, fontSize:20, color:nc.color }}>{nc.texto}</div>
                  <Badge nivel={nivelFatiga} />
                  <div style={{ fontSize:12, color:t.textMuted, lineHeight:1.5 }}>{nc.desc}</div>
                  {estadoFatiga === 'Rostro no detectado' && (
                    <div style={{ background:'rgba(245,158,11,.12)', border:'1px solid rgba(245,158,11,.3)',
                      borderRadius:10, padding:'8px 14px', fontSize:11, color:'#f59e0b' }}>
                      ⚠️ Colócate frente a la cámara
                    </div>
                  )}
                </div>

                {/* Botón Detección de Fatiga */}
                <div
                  onClick={abrirDeteccion}
                  style={{
                    background:'linear-gradient(135deg,rgba(39,139,245,.2),rgba(0,229,200,.12))',
                    border:`1px solid ${t.primary}55`,
                    borderRadius:16, padding:'18px 20px', cursor:'pointer',
                    display:'flex', alignItems:'center', gap:14,
                    transition:'all .25s',
                  }}
                  onMouseEnter={e => {
                    e.currentTarget.style.transform='translateY(-2px)';
                    e.currentTarget.style.boxShadow='0 8px 28px rgba(39,139,245,.3)';
                  }}
                  onMouseLeave={e => {
                    e.currentTarget.style.transform='translateY(0)';
                    e.currentTarget.style.boxShadow='none';
                  }}
                >
                  <div style={{
                    background:'linear-gradient(135deg,#278BF5,#00e5c8)',
                    width:46, height:46, borderRadius:12, flexShrink:0,
                    display:'flex', alignItems:'center', justifyContent:'center',
                    fontSize:22, boxShadow:'0 4px 16px rgba(39,139,245,.4)',
                  }}>⚡</div>
                  <div style={{ flex:1 }}>
                    <div style={{ fontWeight:700, fontSize:14, color:t.text }}>Detección de Fatiga</div>
                    <div style={{ fontSize:11, color:t.textMuted, marginTop:2 }}>
                      Análisis completo · Liveness · IA
                    </div>
                  </div>
                  <span style={{ color:t.primary, fontSize:20 }}>→</span>
                </div>
              </div>
            </div>

            {/* Tips rápidos */}
            <div style={card(t)}>
              <SectionTitle icon="💡" label="Tips de bienestar" color="#f59e0b" t={t} />
              <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit,minmax(200px,1fr))', gap:10 }}>
                {[
                  ['👁️','Regla 20-20-20','Cada 20 min, mira 6m por 20 segundos'],
                  ['💧','Hidratación','Toma agua cada 30 minutos'],
                  ['🧘','Microdescansos','5 min de pausa cada hora'],
                  ['🌞','Iluminación','Luz brillante reduce somnolencia'],
                ].map(([ic, tit, desc]) => (
                  <div key={tit} style={{
                    background:`${t.primary}08`, border:`1px solid ${t.border}`,
                    borderRadius:12, padding:'12px 14px',
                    display:'flex', gap:10, alignItems:'flex-start',
                  }}>
                    <span style={{ fontSize:20 }}>{ic}</span>
                    <div>
                      <div style={{ fontWeight:600, fontSize:13, color:t.text }}>{tit}</div>
                      <div style={{ fontSize:11, color:t.textMuted, marginTop:3 }}>{desc}</div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* ═══ TAB: HISTORIAL ═══ */}
        {tab === 'historial' && (
          <SeccionHistorial userId={user.id_usuario} t={t} />
        )}

        {/* ═══ TAB: PERFIL ═══ */}
        {tab === 'perfil' && perfil && (
          <SeccionPerfil user={user} perfil={perfil} onSave={recargarPerfil} t={t} />
        )}
      </div>

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Sora:wght@300;400;600;700;800&display=swap');
        @keyframes pulse {
          0%,100%{opacity:1} 50%{opacity:.4}
        }
        * { box-sizing: border-box; }
        body { margin:0; }
        ::-webkit-scrollbar { width:6px; }
        ::-webkit-scrollbar-track { background:transparent; }
        ::-webkit-scrollbar-thumb { background:rgba(39,139,245,.3); border-radius:6px; }
      `}</style>
    </div>
  );
}
